import{_ as o,o as t,c as a,an as r}from"./chunks/framework.D5fFzH9V.js";const p=JSON.parse('{"title":"About the handbook","description":"What this handbook is, who it’s for, and how to contribute.","frontmatter":{"description":"What this handbook is, who it’s for, and how to contribute."},"headers":[],"relativePath":"about-the-handbook.md","filePath":"about-the-handbook.md"}'),n={name:"about-the-handbook.md"};function i(s,e,h,l,d,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /about-the-handbook.md for this page in Markdown format</div><h1 id="about-the-handbook" tabindex="-1">About the handbook <a class="header-anchor" href="#about-the-handbook" aria-label="Permalink to &quot;About the handbook&quot;">​</a></h1><p>This is our public handbook, our main source of truth about how we deliver our offensive security services (inspired by <a href="https://handbook.gitlab.com/handbook/" target="_blank" rel="noreferrer">GitLab</a> and <a href="https://handbook.opencoreventures.com/" target="_blank" rel="noreferrer">OCV</a>).</p><p>We encourage our employees to use the handbook during the daily work.</p><p>We try to publish content that our employees, clients or other pentesters might benefit from. The handbook is opinionated and no legal or binding advice to those outside of our company.</p><p>Our handbook should be complete enough that a new employee doesn&#39;t need extensive onboarding to get to know our style of working and our approach to offensive security.</p><p>This handbook is a constant work in progress and follows an iterative approach. We are currently in the process of moving our internal documentation to this public handbook. Things might be missing due to several reasons (privacy, security, copyright, etc.).</p><p>It is okay to be messy. Let&#39;s improve iteratively. Better done than perfect.</p><h2 id="style-guide" tabindex="-1">Style guide <a class="header-anchor" href="#style-guide" aria-label="Permalink to &quot;Style guide&quot;">​</a></h2><ul><li>Front-load essential information.</li><li>Write in present tense.</li><li>Prefer active voice if possible.</li><li>Avoid filler words.</li><li>Use <a href="https://www.grammarly.com/blog/sentences/title-case-sentence-case/" target="_blank" rel="noreferrer">sentence case</a> for titles.</li><li>Avoid typos.</li></ul><p>You can use AI to suggest improvements to your text (include the style guide in your prompt).</p><h2 id="making-changes" tabindex="-1">Making changes <a class="header-anchor" href="#making-changes" aria-label="Permalink to &quot;Making changes&quot;">​</a></h2><h3 id="for-externals" tabindex="-1">For externals <a class="header-anchor" href="#for-externals" aria-label="Permalink to &quot;For externals&quot;">​</a></h3><p><a href="https://github.com/Syslifters/handbook/issues" target="_blank" rel="noreferrer">Open an issue</a> and describe your suggestions and improvements. Thank you for contributing. ❤️</p><h3 id="for-employees" tabindex="-1">For employees <a class="header-anchor" href="#for-employees" aria-label="Permalink to &quot;For employees&quot;">​</a></h3><p>The handbook is hosted in our internal <a href="https://gitlab.internal.syslifters.com/docs/public/" target="_blank" rel="noreferrer">GitLab</a>. Read <a href="/making-changes">how to make changes</a> there.</p>',16)])])}const b=o(n,[["render",i]]);export{p as __pageData,b as default};
